package com.hiliving.content.news;import com.hiliving.api.ApiResponse;import jakarta.validation.Valid;import jakarta.validation.constraints.*;import org.springframework.http.*;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController class PublicNewsController{private final NewsService service;PublicNewsController(NewsService service){this.service=service;}@GetMapping("/api/v1/news")ApiResponse<List<NewsResponse>> list(){return ApiResponse.of(service.publicList());}@GetMapping("/api/v1/news/{slug}")ApiResponse<NewsResponse> find(@PathVariable String slug){return ApiResponse.of(service.publicFind(slug));}}
@Validated@RestController@RequestMapping("/api/v1/admin/news")class AdminNewsController{private final NewsService service;AdminNewsController(NewsService service){this.service=service;}@GetMapping ApiResponse<List<NewsResponse>> list(@RequestParam(required=false)@Size(max=100)String search){return ApiResponse.of(service.adminList(search));}@GetMapping("/{id}")ApiResponse<NewsResponse> find(@PathVariable@Positive Long id){return ApiResponse.of(service.find(id));}@PostMapping@ResponseStatus(HttpStatus.CREATED)ApiResponse<NewsResponse> create(@Valid@RequestBody NewsRequest r){return ApiResponse.of(service.create(r));}@PatchMapping("/{id}")ApiResponse<NewsResponse> update(@PathVariable@Positive Long id,@Valid@RequestBody NewsRequest r){return ApiResponse.of(service.update(id,r));}@DeleteMapping("/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)void delete(@PathVariable@Positive Long id){service.delete(id);}}
